const response = $input.item.json || {};
const issues = Array.isArray(response.issues) ? response.issues : [];
let staticData = {};
try {
  staticData = $getWorkflowStaticData('global');
} catch (error) {
  staticData = {};
}
staticData.processedReadyForQa = staticData.processedReadyForQa || {};

function adfToText(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(adfToText).filter(Boolean).join('\n');
  if (typeof value === 'object') {
    if (typeof value.text === 'string') return value.text;
    if (Array.isArray(value.content)) return value.content.map(adfToText).filter(Boolean).join(value.type === 'paragraph' ? ' ' : '\n');
    if (typeof value.value === 'string') return value.value;
    if (typeof value.displayName === 'string') return value.displayName;
    if (typeof value.name === 'string') return value.name;
  }
  return '';
}

function asText(value) {
  if (value === null || value === undefined) return '';
  if (typeof value === 'string') return value;
  const adf = adfToText(value);
  if (adf) return adf;
  try { return JSON.stringify(value); } catch (error) { return String(value); }
}

function listNames(value) {
  if (!Array.isArray(value)) return [];
  return value.map(item => {
    if (typeof item === 'string') return item;
    if (item && typeof item === 'object') return item.name || item.value || item.displayName || '';
    return '';
  }).filter(Boolean);
}

function acceptanceCriteria(fields) {
  return asText(
    fields.acceptanceCriteria ||
    fields.acceptance_criteria ||
    fields.customfield_acceptance_criteria ||
    fields.customfield_10040 ||
    fields.customfield_10041 ||
    ''
  );
}

const out = [];
for (const issue of issues) {
  const fields = issue.fields || {};
  const statusName = fields.status?.name || '';
  if (String(statusName).toLowerCase() !== 'ready for qa') continue;

  const issueKey = issue.key || '';
  const updated = fields.updated || '';
  const dedupeKey = `${issueKey}:${updated}`;
  if (staticData.processedReadyForQa[dedupeKey]) continue;

  const selfUrl = issue.self || '';
  const jiraBaseUrl = selfUrl.includes('/rest/api') ? selfUrl.split('/rest/api')[0] : '';
  const description = asText(fields.description);
  const summary = fields.summary || '';
  const issueType = fields.issuetype?.name || '';
  const labels = Array.isArray(fields.labels) ? fields.labels : [];
  const components = listNames(fields.components);

  out.push({
    json: {
      issueKey,
      updated,
      dedupeKey,
      statusName,
      summary,
      description,
      issueType,
      jiraBrowseUrl: jiraBaseUrl && issueKey ? `${jiraBaseUrl}/browse/${issueKey}` : issueKey,
      ticket: {
        key: issueKey,
        summary,
        issueType,
        description,
        acceptanceCriteria: acceptanceCriteria(fields),
        labels,
        components
      }
    }
  });
}

return out;

const ticket = $('Keep New Ready For QA Tickets').item.json;
const generated = $input.item.json || {};
const testCases = generated.test_cases || '';
const repos = Array.isArray(generated.grounded_repos) ? generated.grounded_repos : [];
const preview = testCases.length > 2500 ? `${testCases.slice(0, 2500)}\n...truncated in Slack, full test cases were added as a Jira comment.` : testCases;
const jiraComment = `AI generated test cases for Ready For QA.\n\nGrounded repos: ${repos.join(', ') || 'auto-detected'}\nSemantic hits: ${generated.semantic_hits_count ?? 0}\nFiles touched: ${generated.files_touched_count ?? 0}\n\n${testCases}`.slice(0, 30000);
const slackText = `Test cases generated for ${ticket.issueKey}\nStatus: ${ticket.statusName}\nSummary: ${ticket.summary}\nGrounded repos: ${repos.join(', ') || 'auto-detected'}\n\n${preview}\n\n${ticket.jiraBrowseUrl}`;
return [{
  json: {
    issueKey: ticket.issueKey,
    updated: ticket.updated,
    dedupeKey: ticket.dedupeKey,
    jiraBrowseUrl: ticket.jiraBrowseUrl,
    jiraComment,
    slackText,
    testCases,
    generated
  }
}];

const item = $('Format Testcase Outputs').item.json;
try {
  const staticData = $getWorkflowStaticData('global');
  staticData.processedReadyForQa = staticData.processedReadyForQa || {};
  staticData.processedReadyForQa[item.dedupeKey] = {
    issueKey: item.issueKey,
    updated: item.updated,
    processedAt: new Date().toISOString()
  };
} catch (error) {
  // Static data is unavailable in some test contexts; do not fail the workflow.
}
return [{ json: { ok: true, issueKey: item.issueKey, markedProcessed: true } }];
